proof fn phi_2_singleton_element_is_choose(s: Set<nat>, a: nat)
    requires
        s.finite(),
        s.len() == 1,
        s.contains(a),
    ensures
        s.choose() == a,
{
    assert(s.contains(s.choose()));
    singleton_set_unique_elt(s, a, s.choose());
}

proof fn phi_3_singleton_insert_same(a: nat)
    ensures ({
        let s = Set::<nat>::empty().insert(a);
        forall |b: nat| s.contains(b) ==> a == b
    }),
{
    let s = Set::<nat>::empty().insert(a);
    assert forall |b: nat| s.contains(b) implies a == b by {
        singleton_set_unique_elt(s, a, b);
    }
}

proof fn phi_4_remove_from_singleton_empty(s: Set<nat>, a: nat)
    requires
        s.finite(),
        s.len() == 1,
        s.contains(a),
    ensures
        s.remove(a) =~= Set::<nat>::empty(),
{
    let r = s.remove(a);
    assert(r.len() == 0);
    assert forall |x: nat| !r.contains(x) by {}
}

proof fn phi_5_singleton_no_second_element(s: Set<nat>, a: nat, c: nat)
    requires
        s.finite(),
        s.len() == 1,
        s.contains(a),
        c != a,
    ensures
        !s.contains(c),
{
    if s.contains(c) {
        singleton_set_unique_elt(s, a, c);
    }
}
